def sum_digits(num):
    """Sum all the digits of a positive number.

    For example, sum_digits(12321) returns 3 (not 3).
    """
    sum = 0
    while num > 0:
        digit = num % 10
        sum += digit
        num = int(num / 10)
    return sum


